import sys

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    A = list(map(int, input[1:]))

    positions = {}
    for idx, color in enumerate(A):
        if color not in positions:
            positions[color] = []
        positions[color].append(idx + 1)  # positions are 1-based

    count = 0
    for color in range(1, N + 1):
        pos1, pos2 = positions[color]
        if abs(pos1 - pos2) == 2:
            count += 1
    print(count)

if __name__ == "__main__":
    main()
